import {
  Controller,
  Post,
  Get,
  UseGuards,
  Req,
  Res,
  Body,
} from '@nestjs/common';
import { AuthService } from './auth.service';
import { AuthGuard } from '@nestjs/passport';
import type { Response } from 'express';
import { CreateUserDto } from '../user/dto/create-user.dto';

@Controller('auth')
export class AuthController {
  constructor(private readonly authService: AuthService) {}

  @UseGuards(AuthGuard('local'))
  @Post('login')
  async login(@Req() req: any, @Res() res: Response) {
    const loginResult = await this.authService.login(req.user);
    console.log("🚀 ~ AuthController ~ login ~ loginResult:", loginResult)

    // If it's a browser request (Accept: text/html), redirect or return success
    // eslint-disable-next-line @typescript-eslint/no-unsafe-call
    if (req.accepts('html')) {
      // Manual session setup if not handled automatically by Passport
      req.session.loggedin = true;
      req.session.username = req.user.username;
      req.session.balance = req.user.balance;
      req.session.file_history = req.user.file_history;
      req.session.account_no = req.user.account_no;

      return res.redirect('/');
    }

    return res.json(loginResult);
  }

  @Post('newlogin')
  async newLogin(
    @Body() createUserDto: CreateUserDto,
    @Res() res: Response,
    @Req() req: any,
  ) {
    try {
      const user = await this.authService.newLogin(createUserDto);

      if (req.accepts('html')) {

        req.session.loggedin = true;

        req.session.username = user.username;

        req.session.balance = user.balance;

        req.session.file_history = user.file_history;

        req.session.account_no = user.account_no;

        return res.redirect('/');
      }

      return res.json(this.authService.login(user));
    } catch (error) {
      // Em uma aplicação real, seria melhor redirecionar com uma mensagem de erro.
      const errorMessage = error instanceof Error ? error.message : 'Ocorreu um erro desconhecido.';
      return res.status(400).send(`<html><body><h2>Não foi possível criar a conta.</h2><p>${errorMessage}</p><a href="/">Voltar</a></body></html>`);
    }
  }

  @Get('logout')
  async logout(@Req() req: any, @Res() res: Response) {
    req.logout((err: any) => {
      if (err) {
        return res.status(500).json({ message: 'Error logging out' });
      }
      req.session.destroy();
      res.redirect('/');
    });
  }
}

import bcrypt from 'bcrypt';
import { Injectable } from '@nestjs/common';
import { JwtService } from '@nestjs/jwt';
import { UserService } from '../user/user.service';
import { IPayload, UserWithoutPassword } from './typings/auth';
import { CreateAuthDto } from './dto/create-auth.dto';

@Injectable()
export class AuthService {
  constructor(
    private userService: UserService,
    private jwtService: JwtService,
  ) {}

  async validateUser(username: string, pass: string): Promise<UserWithoutPassword | null> {
    const userData = await this.userService.findByUsername(username);

    if (!userData || !userData.password) {
      return null;
    }

    const isPasswordMatching = await bcrypt.compare(pass, userData.password);

    if (!isPasswordMatching) {
      return null;
    }

    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    const { password, ...result } = userData;
    return result;
  }

  async newLogin(createAuthDto: CreateAuthDto) {
    return this.userService.create(createAuthDto);
  }

  login(user: IPayload) {
    const payload = { username: user.username, sub: user.id };
    return {
      access_token: this.jwtService.sign(payload),
    };
  }
}

import bcrypt from 'bcrypt';
import { Injectable, ConflictException } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { User } from './entities/user.entity';
import { CreateUserDto } from './dto/create-user.dto';
import { generateAccountNo } from '../../utils/generateAccount';

@Injectable()
export class UserService {
  constructor(
    @InjectRepository(User)
    private usersRepository: Repository<User>,
  ) {}

  async create(createUserDto: CreateUserDto): Promise<User> {
    const existingUser = await this.findByUsername(createUserDto.username);
    if (existingUser) {
      throw new ConflictException('O nome de usuário já está em uso.');
    }

    const saltRounds = 10;
    const hashedPassword = await bcrypt.hash(createUserDto.password, saltRounds);
    const balanceInitial = 0;
    const user = this.usersRepository.create({
      username: createUserDto.username,
      password: hashedPassword,
      balance: balanceInitial,
      file_history: '',
      account_no: generateAccountNo(),
    });

    try {
      return await this.usersRepository.save(user);
    } catch (error: any) {
      if (error.code === 'SQLITE_CONSTRAINT' || error.message?.includes('UNIQUE constraint failed')) {
        throw new ConflictException('O nome de usuário já está em uso.');
      }
      throw error;
    }
  }
  findByUsername(username: string): Promise<User | null> {
    return this.usersRepository.findOne({ where: { username } });
  }
}

import { PassportSerializer } from '@nestjs/passport';
import { Injectable } from '@nestjs/common';
import { UserService } from '../../user/user.service';
import { User } from '../../user/entities/user.entity';

@Injectable()
export class SessionSerializer extends PassportSerializer {
  constructor(private readonly userService: UserService) {
    super();
  }

  serializeUser(user: User, done: (err: Error | null, user: any) => void) {
    done(null, { id: user.id, username: user.username });
  }

  async deserializeUser(payload: any, done: (err: Error | null, user: any) => void) {
    const user = await this.userService.findByUsername(payload.username);
    done(null, user);
  }
}

